UPDATE app_schedule_type
type_code = #{type_code}, type_name = #{type_name}, sort_no = #{sort_no}, status = #{status}, remark = #{remark}, update_time = DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s'),
WHERE id = #{id}

mapper.select:
SELECT  FROM app_schedule_type su WHERE 1=1
AND su.id = #{id}
AND su.type_code = #{type_code}
AND su.type_name LIKE CONCAT('%',#{type_name},'%')
AND su.status = #{status}
ORDER BY su.sort_no ASC, su.id ASC

